@return Vector of Inventorys.
/
public Vector<Inventory> getItems()
{
Vector<Inventory> items = new Vector<Inventory>();
int count = Util.getCategoryStrings().length;
for (int i = 0; i < count; i++)
{
items.addAll(getItemsByCategory(i));
}
return items;
}

